/**
 * Respondent-signature election prediction.
 *
 * Distance formula: weighted Euclidean against each candidate's node profile,
 * where each node's weight is the respondent's archetype salience multiplied
 * by an era-activation multiplier from era-activations.json (1x / 2x / 3x per
 * year × node). See era-activations.ts for the canonical activation map and
 * the multiplier semantics. The prior dense-vector eraWeight + 60/40 blend
 * has been removed; activation-multiplier is the sole era mechanism.
 *
 * Output: per-candidate distances + an engagement-driven clearing bar that
 * decides vote vs abstain.
 *
 * Anti-position branch is intentionally skipped: respondents don't carry
 * anti markers. The archetype classification layer still uses anti.
 */

import type { NodeSignature } from "../engine/respondentSignature.js";
import type { CandidateProfile } from "./candidates.js";
import type { ElectionContext, ContinuousNodeId } from "./activation.js";
import type { EngagementLevel } from "../engine/engagementLabel.js";
import type {
  PartyID,
  TrbAnchor,
  TrbAnchorDist,
  MorBoundariesNodeState,
} from "../types.js";
import { getActivationMultiplier } from "./era-activations.js";
import { getNonIdeologicalModifier, historicalToCanonical } from "./non-ideological-modifiers.js";
import { morTargetVectorDistance, boundaryLoad, moralCircleDistance } from "../engine/math.js";

// Candidate-side TRB anchor encoding (P3.2, ADR-009). Each anchor predicts
// different identity-driven appeal:
//   national      — appeals to nationalist identity voters
//   ideological   — appeals to ideological-identity voters
//   religious     — appeals to religious-identity voters
//   class         — appeals to class-identity voters
//   ethnic_racial — appeals via ethnic/racial identity (very modern; risky for
//                   pre-1968 elections so use sparingly)
//   gender        — gender-identity appeal
//   sexual        — LGBTQ-coded
//   global        — cosmopolitan, internationalist
//   mixed_none    — no dominant identity hook
//
// Encoded only for candidates where the anchor is a meaningfully distinct
// part of their political appeal. Many candidates leave it null (no signal).
const TRB_ANCHOR_BY_CANDIDATE: Record<string, TrbAnchor> = {
  // Modern-era — strongest signals
  "Trump_2016": "national",
  "Trump_2020": "national",
  "Trump_2024": "national",
  "Sanders_2016": "class",
  "Sanders_2016_primary": "class", // not in main set but reserved
  "H. Clinton_2016": "ideological",
  "Obama_2008": "ideological",
  "Obama_2012": "ideological",
  "Biden_2020": "national",
  "Harris_2024": "ideological",
  "Romney_2012": "ideological",
  "McCain_2008": "national",
  "Bush_2000": "religious",
  "Bush_2004": "religious",
  "Bush_1988": "national",
  "Bush_1992": "national",
  "Reagan_1980": "ideological",
  "Reagan_1984": "ideological",
  "Carter_1976": "religious",
  "Carter_1980": "religious",
  "Goldwater_1964": "ideological",
  "Johnson_1964": "class",
  "Kennedy_1960": "national",
  "Nixon_1968": "national",
  "Nixon_1972": "national",
  "Roosevelt_1932": "class",
  "Roosevelt_1936": "class",
  "Roosevelt_1940": "class",
  "Roosevelt_1944": "class",
  "Truman_1948": "class",
  "Eisenhower_1952": "national",
  "Eisenhower_1956": "national",
  "Wallace_1968": "ethnic_racial", // segregationist
  "Thurmond_1948": "ethnic_racial", // Dixiecrat
  // Third party / independent
  "Nader_2000": "ideological",
  "Perot_1992": "class",
  "Perot_1996": "class",
  "Anderson_1980": "ideological",
};

const TRB_ANCHOR_ORDER: TrbAnchor[] = [
  "national", "ideological", "religious", "class", "ethnic_racial",
  "gender", "sexual", "global", "mixed_none",
];

function getCandidateAnchor(cand: CandidateProfile): TrbAnchor | null {
  const key = `${cand.name}_${cand.year}`;
  return TRB_ANCHOR_BY_CANDIDATE[key] ?? null;
}

function anchorDistanceContribution(
  cand: CandidateProfile,
  anchorDist: TrbAnchorDist | null | undefined,
): { contribution: number; weight: number } {
  if (!anchorDist) return { contribution: 0, weight: 0 };
  const anchor = getCandidateAnchor(cand);
  if (!anchor) return { contribution: 0, weight: 0 };
  const idx = TRB_ANCHOR_ORDER.indexOf(anchor);
  if (idx < 0) return { contribution: 0, weight: 0 };
  // userMassOnCandidateAnchor: 0-1. Higher = more aligned.
  const userMass = anchorDist[idx] ?? 0;
  // Convert to distance-like contribution. Same scale as categorical (0-4).
  const baseSal = 0.7; // small but nonzero — anchor is a real predictor
  const effectiveSal = Math.pow(baseSal, SALIENCE_POWER);
  const diff2 = (1 - userMass) * 4;
  return { contribution: effectiveSal * diff2, weight: effectiveSal };
}

// Partisan-loyalty multiplier (added 2026-04-24 per ADR-007).
//
// Pure ideological-distance scoring missed a major real-world voting force:
// people with strong party identification vote their party regardless of
// small ideological shifts in candidates. A registered Democrat with high PF
// votes Democratic ~95%+ of the time post-1970 even if the candidate is
// ideologically off in some dimension.
//
// Mechanism: when the respondent has a partyID, multiply the distance to each
// candidate by 1 + PARTY_LOYALTY_BASE × (PF/5) × outOfPartyFactor. PF ranges
// 1-5, so a high-PF (5) Democrat gets a 1 + 0.40 × 1.0 = 1.40× distance bump
// to non-Democratic candidates. A casual (PF=2) Democrat gets ~1.16×. An
// independent (partyID='I') gets no multiplier — ideology dominates.
//
// Party-mapping function below handles historical parties (Democratic-Republican
// counts as 'D' for early-19th-century Jeffersonian Democrats; Whig and
// National Republican count as the proto-Republican coalition).
// Default 5.00 (was 3.00 post-Round-2, 1.00 post-Round-1, 0.40 pre-2026-05-08).
// Round-3 sweep (2026-05-09) extended loyalty to {3.0, 3.5, 4.0, 5.0} and
// found the function is monotonically decreasing across that range with
// diminishing returns. loyalty=5.0 won at the upper grid edge with TV 5.96pp.
//
// At 5.0, PF=5 strong partisans face a 1 + 5.0 = 6.0× distance multiplier
// to out-of-party candidates. PF=3 moderate partisans face 1 + 5.0 × 0.6 = 4.0×.
// This is effectively near-deterministic partisan vote-routing for strong
// partisans — moderates still respond to issue-distance differences but
// with heavy bias toward in-party.
//
// Treating this as the calibration ceiling for loyalty. Going higher would
// shave another ~0.3pp but degrades into "model = pid7 lookup" for
// partisans, which over-fits the modern partisan-loyalty pattern. Further
// D/R-gap closure from here requires structural moves (calibration battery,
// hierarchical Bayesian refit, candidate-profile refresh), not constant
// tuning.
const PARTY_LOYALTY_BASE = (() => {
  const env = process.env.PRISM_PARTY_LOYALTY_BASE;
  if (env === undefined) return 5.00;
  const n = Number(env);
  return Number.isFinite(n) && n >= 0 ? n : 5.00;
})();

function candidatePartyToCanonical(party: string): "D" | "R" | "T" | "O" {
  // Map historical / third-party labels to a canonical 4-bucket scheme so
  // the partyID multiplier can decide "is this candidate my party or not?"
  if (party === "Democratic" || party === "Democratic-Republican" ||
      party === "Free Soil" || party === "Dixiecrat") return "D";
  if (party === "Republican" || party === "National Republican" ||
      party === "Federalist" || party === "Whig") return "R";
  if (party === "Independent" || party === "American Independent" ||
      party === "Libertarian" || party === "Green") return "T";
  return "O";
}

/**
 * Derive a 1..5 PF-equivalent from morBoundaries. Mirrors the bridge
 * direction (PF pos → political_tribe boundary up + intensity up): a strongly
 * partisan-fused respondent has high political_tribe boundary AND high
 * intensity. Returns null if morBoundaries is absent (caller falls back to
 * legacy pfPos read).
 */
function pfEquivalentFromMorBoundaries(
  state: MorBoundariesNodeState | null | undefined,
): number | null {
  if (!state) return null;
  const pt = state.boundaries.political_tribe;
  const intensityFactor = state.intensity / 3; // ∈ [0, 1]
  return 1 + 4 * pt * intensityFactor; // ∈ [1, 5]
}

/**
 * ADR-007 (T9): derive a 1..5 PF-equivalent from moralCircle affinity.
 * High political_camp scoped affinity + high intensity03 = strong
 * partisan in-group identity. Read with `state.moralCircle.affinity` —
 * returns null when affinity isn't materialized yet.
 *
 *   politicalCampScoped (0..100) · intensity03Factor (0..1) → pfEquiv (1..5)
 */
function pfEquivalentFromMoralCircle(
  affinity: import("../types.js").MoralCircleAffinity | null | undefined,
): number | null {
  if (!affinity) return null;
  // 2026-05-07 6-scope merge: political_camp folded into ideological. PF
  // partisan-loyalty proxy now reads ideological affinity.
  const ideo = affinity.scopedAffinities.ideological;
  if (ideo === null || ideo === undefined) return null;
  const ideoN = Math.max(0, Math.min(100, ideo)) / 100; // ∈ [0, 1]
  const intensityFactor = Math.max(0, Math.min(1, affinity.intensity03 / 3));
  return 1 + 4 * ideoN * intensityFactor; // ∈ [1, 5]
}

function partisanLoyaltyMultiplier(
  candidateParty: string,
  respondentParty: PartyID | null | undefined,
  pfPos: number | null | undefined,
  electionYear: number,
): number {
  // Era-limit (P3.4): modern Democrat/Republican loyalty doesn't map cleanly
  // backward onto Whigs, Federalists, Free Soilers, Dixiecrats, etc. Pre-1932
  // (the New Deal realignment), partisan-loyalty multiplier is disabled and
  // ideological distance alone governs.
  if (electionYear < 1932) return 1;
  // I (Independent), N (Nothing), O (Other) all behave as "no major-party
  // loyalty": ideological distance alone governs. Only D/R/T carry a loyalty
  // signal — T (member of a third party) gets a bump toward third-party
  // candidates (Roosevelt-1912 Progressive, La Follette, Wallace AIP, Perot,
  // Nader, Anderson) and a small penalty against D/R. O was previously
  // returning the wrong-party penalty against essentially all candidates
  // because no candidate's canonical party is "O" — fixed 2026-05-13.
  if (!respondentParty || respondentParty === "I" || respondentParty === "N" || respondentParty === "O") return 1;
  const candPartyKey = candidatePartyToCanonical(candidateParty);
  const userPartyKey =
    respondentParty === "D" ? "D" :
    respondentParty === "R" ? "R" :
    respondentParty === "T" ? "T" : "O";
  if (candPartyKey === userPartyKey) return 1;
  const pf = Math.max(1, Math.min(5, pfPos ?? 3));
  // PF=5 → 1.40× distance to other-party candidates; PF=1 → 1.08×.
  return 1 + PARTY_LOYALTY_BASE * (pf / 5);
}

// Kill switch: non-ideological modifier layer (economic + incumbency +
// charisma) is on by default as of 2026-04-20 per ADR-004. Set env var
// PRISM_NONIDEO=0 to disable it for debugging; any other value (or unset)
// leaves it enabled. See results/non-ideological-layer/.
const NONIDEO_ENABLED = process.env.PRISM_NONIDEO !== "0";

// SELF-cluster nodes are activation-only per ADR-005. PF still drives the
// party-loyalty multiplier, and TRB still contributes via anchor alignment,
// but neither should be treated as a direct candidate-position distance.
const SCORING_NODES: ContinuousNodeId[] = [
  "MAT", "CD", "CU", "MOR", "PRO", "COM", "ZS",
  "ONT_H", "ONT_S",
];

// 6.E.3a cutover (ADR-006). Continuous nodes whose contribution is folded
// into the compound morBoundaries Layer 1 vector + intensity term when both
// sides carry the new module. Mirrors archetypeDistance's MOR_MODULE_LEGACY
// (PR 6.E.2a) — we use a per-call gate instead of removing them outright,
// so legacy callers (states/candidates without morBoundaries) keep their
// current geometry.
const MOR_MODULE_LEGACY_NODES: ContinuousNodeId[] = ["MOR"];

// Engagement → clearing-bar thresholds in weighted-RMS distance units (0-4 range).
// Originally anchored to the pre-recoding distance distribution (Stage A,
// 2026-04-19). The 2026-04-23 Pass-1 candidate recodings shrank nearest-
// candidate distances system-wide, so the original bars produced ~2-5%
// abstention rates across centroid-sim runs.
// Retuned 2026-04-23 to target ~20% aggregate abstention per user feedback.
// Scaled down ~30% from original values; re-check against centroid-sim if
// distance distribution shifts further.
// 2026-04-23: tightened "highly-engaged" from 2.45 → 1.90 so that voters at the
// top engagement level abstain when no candidate is within a reasonable
// ideological distance — fixes "Kamala voting for Jackson in 1828 because it's
// the less-bad option" artifact. Casual/engaged bars unchanged.
// 2026-04-23 retune: bars scaled up to give uniform-distribution respondents
// realistic vote-through rates (their raw distances are naturally 1.5–2.0 for
// random positions). Highly-engaged kept below 1.90 so Harris-type universalists
// still abstain when their nearest 1828 option is 1.900+ away.
const CLEARING_BAR: Record<EngagementLevel, number> = {
  "apolitical": 0.95,
  "casual": 1.40,
  "engaged": 1.70,
  "highly-engaged": 1.85,
};

export interface CandidateScore {
  name: string;
  party: string;
  /** Values-only distance before moral-floor disqualification penalty. */
  baseIdeologicalDistance: number;
  /** Equal-citizenship incompatibility penalty added in rights-veto contexts. */
  moralFloorPenalty: number;
  /** Short reason when moralFloorPenalty > 0. */
  moralFloorReason?: string;
  /** Values-only distance before non-ideological, party-loyalty, and negative-party modifiers. */
  ideologicalDistance: number;
  /** Economic/incumbency/charisma modifier total subtracted from ideologicalDistance. */
  nonIdeologicalModifier: number;
  /** Distance after non-ideological modifier, before party/negative multipliers. */
  nonIdeologicalAdjustedDistance: number;
  /** Post-1932 out-party multiplier from party ID and PF. */
  partisanMultiplier: number;
  /** Negative-partisanship multiplier for never-vote parties. */
  negativePartisanshipMultiplier: number;
  /** Final predicted-vote distance after all modifiers. */
  distance: number;
}

export interface ElectionPrediction {
  year: number;
  candidates: CandidateScore[];
  clearingBar: number;
  /** Candidate closest on values alone, before non-ideological and party modifiers. */
  nearestByValues: CandidateScore;
  nearest: CandidateScore;
  valuesDecision: "vote" | "abstain";
  decision: "vote" | "abstain";
}

// 2026-04-23: salience power-law weighting.
// Linear salience weighting (sal as a weight directly) caused single-issue
// voters to be diluted by averaging — a voter with sal=3 on MAT and sal=1 on
// everything else only gave MAT 3× the weight of minor issues, not the ~30×
// weight that matches real single-issue behavior. SALIENCE_POWER=2 squares
// the weight, so sal=3 issues dominate (9× vs 1×) while sal=0 still drops
// cleanly to zero contribution.
// Default 1.1 (was 1.3 post-Round-2, 1.5 post-Round-1, 2.0 pre-2026-05-08).
// Round-3 sweep (2026-05-09) refined the optimum on the upper-loyalty axis;
// SALIENCE_POWER showed monotonic but small effect (1.1 < 1.3 < 1.5 in TV).
// Combined with PARTY_LOYALTY_BASE=5.0 for avg-TV 6.85pp → 5.96pp.
const SALIENCE_POWER = (() => {
  const env = process.env.PRISM_SALIENCE_POWER;
  if (env === undefined) return 1.1;
  const n = Number(env);
  return Number.isFinite(n) && n > 0 ? n : 1.1;
})();

// Categorical-node (EPS/AES) weight in the vote-distance metric. Per ADR-009
// (P3.1), categorical nodes were silently absent from predictVote despite
// being measured for archetype matching. Modern elections (esp. 2016/2024)
// are partly style-driven: fighter vs statesman AES, intuitionist vs
// institutionalist EPS predict vote choice. Added here at low base weight
// (0.30 of policy-node base) so style augments — but doesn't dominate —
// ideological alignment. Era-elevated for elections where style was
// historically decisive: 1932 (FDR's vision/fighter persona), 1960 (Kennedy
// charisma), 1980 (Reagan visionary), 2008 (Obama visionary), 2016 (Trump
// fighter vs Clinton statesman), 2020 (Biden statesman vs Trump fighter),
// 2024 (Harris statesman vs Trump fighter).
// Env-var override for calibration sweeps. Default 0.6 unchanged at runtime.
const CATEGORICAL_BASE_SALIENCE = (() => {
  const env = process.env.PRISM_CATEGORICAL_BASE_SALIENCE;
  if (env === undefined) return 0.6;
  const n = Number(env);
  return Number.isFinite(n) && n >= 0 ? n : 0.6;
})();
const STYLE_DRIVEN_ELECTIONS: Record<number, number> = {
  1932: 1.4, 1960: 1.4, 1980: 1.5, 2008: 1.4,
  2016: 2.0, 2020: 1.7, 2024: 1.8,
};

const RIGHTS_VETO_CONTEXTS: Record<number, string> = {
  1824: "Jacksonian exclusion / Native removal and slavery-era citizenship",
  1828: "Jacksonian exclusion / Native removal and slavery-era citizenship",
  1832: "Jacksonian exclusion / Native removal and slavery-era citizenship",
  1836: "Jacksonian exclusion / slavery-era citizenship",
  1840: "Jacksonian exclusion / slavery-era citizenship",
  1844: "slavery expansion and equal citizenship",
  1848: "slavery expansion and equal citizenship",
  1852: "Fugitive Slave Act / slavery accommodation",
  1856: "slavery expansion and equal citizenship",
  1860: "slavery expansion and equal citizenship",
  1864: "slavery / emancipation / equal citizenship",
  1868: "Reconstruction and Black citizenship",
  1872: "Reconstruction and Black citizenship",
  1876: "Reconstruction and Black citizenship",
  1948: "segregation and civil rights",
  1964: "civil rights and segregation",
  1968: "segregation and civil rights backlash",
};

function clamp01(x: number): number {
  return Math.max(0, Math.min(1, x));
}

function moralFloorPenalty(
  sig: NodeSignature,
  cand: CandidateProfile,
  year: number,
  morBoundariesState?: MorBoundariesNodeState | null,
): { penalty: number; reason?: string } {
  const reason = RIGHTS_VETO_CONTEXTS[year];
  if (!reason) return { penalty: 0 };

  // 6.E.3a per-call gate: when both sides have morBoundaries, derive the
  // veto from the new module geometry. Universalist user (low load) +
  // activated (high intensity) penalizes exclusionary candidate (high load).
  if (morBoundariesState && cand.morBoundaries) {
    const userLoad = boundaryLoad(morBoundariesState.boundaries);
    const userIntensity = morBoundariesState.intensity;
    const candLoad = boundaryLoad(cand.morBoundaries.boundaries);
    // Gate analogs to the legacy thresholds (cand.MOR <= 2, sigMOR.pos >= 3.5,
    // sigMOR.sal >= 1.5):
    //   candLoad >= 0.6        → exclusionary candidate (in-group bias)
    //   userLoad <= 0.4        → universalist user (broad moral circle)
    //   userIntensity >= 1.5   → activated user (cares enough to veto)
    if (candLoad < 0.6 || userLoad > 0.4 || userIntensity < 1.5) return { penalty: 0 };
    const universalismStrength = clamp01((0.4 - userLoad) / 0.4);   // 0 at 0.4, 1 at 0
    const intensityStrength = clamp01((userIntensity - 1.5) / 1.5); // 0 at 1.5, 1 at 3
    const severity = candLoad >= 0.85 ? 0.20 : 0;
    const penalty = 0.25 + 0.25 * universalismStrength + 0.25 * intensityStrength + severity;
    return { penalty, reason };
  }

  // Legacy fallback: use MOR pos/sal directly.
  if (cand.MOR > 2) return { penalty: 0 };
  const mor = sig.MOR;
  if (!mor || mor.pos < 3.5 || mor.sal < 1.5) return { penalty: 0 };

  const posStrength = clamp01((mor.pos - 3.5) / 1.5);
  const salStrength = clamp01((mor.sal - 1.5) / 1.5);
  const severity = cand.MOR <= 1 ? 0.20 : 0;
  const penalty = 0.25 + 0.25 * posStrength + 0.25 * salStrength + severity;

  return { penalty, reason };
}

function categoricalDistance(
  cand: CandidateProfile,
  cat: { catDist: number[]; salience?: number } | null,
  nodeName: "EPS" | "AES",
  year: number,
): { contribution: number; weight: number } {
  if (!cat) return { contribution: 0, weight: 0 };
  const candIdx = (cand as unknown as Record<string, number>)[nodeName];
  if (candIdx == null || candIdx < 0 || candIdx >= 6) return { contribution: 0, weight: 0 };
  // 1 - userMassOnCandidateCategory: 0 if user is fully aligned, 1 if fully misaligned.
  const alignment = cat.catDist[candIdx] ?? 0;
  const eraMult = STYLE_DRIVEN_ELECTIONS[year] ?? 1.0;
  const baseSal = CATEGORICAL_BASE_SALIENCE * eraMult;
  const effectiveSal = Math.pow(baseSal, SALIENCE_POWER);
  // Convert alignment (0-1) to a distance-like metric in pos² units (0-16
  // matches the policy-node squared-diff range).
  const diff2 = (1 - alignment) * 4; // alignment=1 → diff²=0 ; alignment=0 → diff²=4
  return { contribution: effectiveSal * diff2, weight: effectiveSal };
}

function ideologicalDistance(
  sig: NodeSignature,
  cand: CandidateProfile,
  ctx: ElectionContext,
  anchorDist?: TrbAnchorDist | null,
  dominantNode?: string | null,
  morBoundariesState?: MorBoundariesNodeState | null,
  moralCircleAffinity?: import("../types.js").MoralCircleAffinity | null,
): number {
  let weightedSumSq = 0;
  let totalWeight = 0;

  // ADR-007 Step 5: when both respondent and candidate carry moralCircle
  // affinity, prefer the explicit-affinity geometry over the legacy
  // boundary-vector geometry. Per ADR §"Candidate Matching Direction":
  // moralCircleDistance blends universal-affinity scalar diff (0.40) +
  // excess-vector L2 (0.40) + active-boundary Jaccard miss (0.20) — this
  // captures "universalist with national lean" differently from
  // "low-baseline with national strength", which the legacy
  // morTargetVectorDistance cannot. Falls back to the ADR-006 morModule
  // branch when either side lacks the new field.
  const useMoralCircle = !!moralCircleAffinity && !!cand.moralCircle;
  // 6.E.3a per-call gate: when both respondent and candidate carry
  // morBoundaries, drop legacy MOR + skip the trbAnchor side-channel and
  // fold both into one morModule contribution computed below. Otherwise
  // (legacy state or candidate without the field) the old per-node MOR +
  // trbAnchor contributions still fire — protects callers that build
  // signatures by hand and don't initialize morBoundaries.
  const useMorModule = !useMoralCircle && !!morBoundariesState && !!cand.morBoundaries;

  for (const node of SCORING_NODES) {
    if ((useMorModule || useMoralCircle) && (MOR_MODULE_LEGACY_NODES as string[]).includes(node)) continue;
    const entry = sig[node];
    if (!entry) continue;

    const candPos = (cand as unknown as Record<string, number>)[node];
    if (candPos == null) continue;

    const rawSal = entry.sal * getActivationMultiplier(ctx.year, node);
    let effectiveSal = Math.pow(rawSal, SALIENCE_POWER);
    // Single-issue dominance amplifier (P3.6). If this node has been
    // flagged as the user's dominant single issue, give its contribution
    // a 1.5× multiplier so it can override otherwise-close candidates.
    if (dominantNode === node) effectiveSal *= 1.5;

    const diff = entry.pos - candPos;
    weightedSumSq += effectiveSal * diff * diff;
    totalWeight += effectiveSal;
  }

  // EPS / AES categorical contributions (P3.1, ADR-009).
  const epsSig = sig.EPS as { catDist?: number[]; pos?: number; sal?: number } | undefined;
  const aesSig = sig.AES as { catDist?: number[]; pos?: number; sal?: number } | undefined;
  if (epsSig?.catDist) {
    const r = categoricalDistance(cand, { catDist: epsSig.catDist }, "EPS", ctx.year);
    weightedSumSq += r.contribution;
    totalWeight += r.weight;
  }
  if (aesSig?.catDist) {
    const r = categoricalDistance(cand, { catDist: aesSig.catDist }, "AES", ctx.year);
    weightedSumSq += r.contribution;
    totalWeight += r.weight;
  }

  // ── Compound moral-circle Layer 1 contribution (ADR-006 PR 6.E.3a) ────
  // One boundary-vector term + one intensity-derived weight, replacing the
  // legacy MOR per-node contribution AND the trbAnchor side-channel. The
  // morTargetVectorDistance returns ∈ [0,1] over 7 boundaries; we scale to
  // the same 0..4 diff² range used by per-node terms. Salience-equivalent
  // is intensity × era-multiplier (using "MOR" as the closest era proxy
  // because morBoundaries replaces what era-activations.json calls "MOR").
  //
  // Layer 2 (membership lock-and-key) is intentionally NOT implemented in
  // 6.E.3a. Real Layer 2 per ADR-006 requires comparing respondent
  // `morMembership` to candidate `morMembership`, with a mismatch penalty
  // as well as a match credit. Layer 2 v1 applies only to `ethnic_racial`,
  // `religious`, `class`, and `gender`. `political_tribe` remains Layer 1
  // only until/unless the existing partisan multiplier is migrated into
  // Layer 2. `national` and `ideological` are explicitly excluded.
  //
  // The respondent side has no morMembership field threaded yet (lands
  // with the membership question in 6.F or later). Until then we ship
  // Layer 1 only — a same-boundary credit without the membership check
  // would produce false-positive "matches" (e.g., any nationalist
  // respondent appearing to "match" any national-anchored candidate
  // regardless of membership), which is exactly the failure mode caught
  // on 6.E.3a review (Sam, 2026-04-30).
  if (useMoralCircle) {
    // ADR-007 Step 5: explicit-affinity geometry. moralCircleDistance
    // returns ∈ [0, 1] (universal 0.40 + excess L2 0.40 + Jaccard 0.20),
    // same range as morTargetVectorDistance. Map to pos² 0..16 scale via
    // ×4 like the morModule branch. Salience-equivalent uses
    // intensity03 (the moralCircle-side equivalent of morBoundariesState
    // intensity), with the same era-multiplier proxy via "MOR".
    const dist01 = moralCircleDistance(moralCircleAffinity!, cand.moralCircle!);
    const diff = dist01 * 4;
    const intensity03 = moralCircleAffinity!.intensity03;
    const eraMult = getActivationMultiplier(ctx.year, "MOR");
    const rawSal = intensity03 * eraMult;
    let effectiveSal = Math.pow(rawSal, SALIENCE_POWER);
    if (dominantNode === "MOR" || dominantNode === "TRB" || dominantNode === "PF") {
      effectiveSal *= 1.5;
    }
    weightedSumSq += effectiveSal * diff * diff;
    totalWeight += effectiveSal;
  } else if (useMorModule) {
    const respBd = morBoundariesState!.boundaries;
    const candBd = cand.morBoundaries!.boundaries;
    const vd = morTargetVectorDistance(respBd, candBd);
    const diff = vd * 4; // map [0,1] vector distance into pos² 0..16 scale
    const intensity = morBoundariesState!.intensity;
    const eraMult = getActivationMultiplier(ctx.year, "MOR");
    const rawSal = intensity * eraMult;
    let effectiveSal = Math.pow(rawSal, SALIENCE_POWER);
    if (dominantNode === "MOR" || dominantNode === "TRB" || dominantNode === "PF") {
      effectiveSal *= 1.5;
    }
    weightedSumSq += effectiveSal * diff * diff;
    totalWeight += effectiveSal;
  } else if (anchorDist) {
    // Legacy fallback: TRB anchor alignment (P3.2, ADR-009). User's anchor
    // distribution vs candidate's encoded anchor identity. Only fires for
    // candidates with an entry in TRB_ANCHOR_BY_CANDIDATE.
    const r = anchorDistanceContribution(cand, anchorDist);
    weightedSumSq += r.contribution;
    totalWeight += r.weight;
  }

  const ideological = totalWeight > 0 ? Math.sqrt(weightedSumSq / totalWeight) : 4;
  return ideological;
}

export function predictVote(
  sig: NodeSignature,
  candidates: CandidateProfile[],
  ctx: ElectionContext,
  engagement: EngagementLevel,
  partyID?: PartyID | null,
  anchorDist?: TrbAnchorDist | null,
  negativeParties?: Set<string> | null,
  strategicVoting?: boolean,
  dominantNode?: string | null,
  morBoundariesState?: MorBoundariesNodeState | null,
  moralCircleAffinity?: import("../types.js").MoralCircleAffinity | null,
): ElectionPrediction {
  // ADR-007 (T9): prefer PF-equivalent derived from moralCircle affinity
  // (political_camp scoped × intensity03). Falls back to ADR-006
  // morBoundaries-derived PF, then to legacy sig.PF.pos.
  const pfFromMc = pfEquivalentFromMoralCircle(moralCircleAffinity);
  const pfFromMor = pfEquivalentFromMorBoundaries(morBoundariesState);
  const pfPos = pfFromMc ?? pfFromMor ?? sig.PF?.pos ?? null;
  const scored: CandidateScore[] = candidates.map(c => {
    const baseValuesDist = ideologicalDistance(sig, c, ctx, anchorDist, dominantNode, morBoundariesState, moralCircleAffinity);
    const moralFloor = moralFloorPenalty(sig, c, ctx.year, morBoundariesState);
    const valuesDist = baseValuesDist + moralFloor.penalty;
    const nonIdeologicalModifier = NONIDEO_ENABLED
      ? getNonIdeologicalModifier(
          ctx.year,
          historicalToCanonical(c.name, c.year),
        ).total
      : 0;
    const nonIdeologicalAdjustedDistance = valuesDist - nonIdeologicalModifier;
    const loyaltyMult = partisanLoyaltyMultiplier(c.party, partyID, pfPos, ctx.year);
    // Negative-partisanship hard penalty (P3.3). Multiplies distance by
    // 1.8x for parties the user has flagged as never-vote.
    let negPenalty = 1.0;
    if (negativeParties) {
      const cp = candidatePartyToCanonical(c.party);
      if ((cp === "D" && negativeParties.has("D")) ||
          (cp === "R" && negativeParties.has("R")) ||
          (cp === "T" && negativeParties.has("T"))) {
        negPenalty = 1.8;
      }
    }
    return {
      name: c.name,
      party: c.party,
      baseIdeologicalDistance: baseValuesDist,
      moralFloorPenalty: moralFloor.penalty,
      ...(moralFloor.reason ? { moralFloorReason: moralFloor.reason } : {}),
      ideologicalDistance: valuesDist,
      nonIdeologicalModifier,
      nonIdeologicalAdjustedDistance,
      partisanMultiplier: loyaltyMult,
      negativePartisanshipMultiplier: negPenalty,
      distance: nonIdeologicalAdjustedDistance * loyaltyMult * negPenalty,
    };
  });

  const nearestByValues = scored.reduce((a, b) =>
    (a.ideologicalDistance <= b.ideologicalDistance ? a : b)
  );
  let nearest = scored.reduce((a, b) => (a.distance <= b.distance ? a : b));
  const clearingBar = CLEARING_BAR[engagement];

  // Strategic voting (P3.5). If user is a strategic voter AND nearest is a
  // third-party candidate AND a major-party candidate is within 0.4 distance,
  // re-route to the lesser-evil major-party. Captures the "I'd prefer Nader
  // but I voted Gore" pattern.
  if (strategicVoting) {
    const nearestCanon = candidatePartyToCanonical(nearest.party);
    if (nearestCanon === "T" || nearestCanon === "O") {
      const majorWithin = scored
        .filter(s => {
          const k = candidatePartyToCanonical(s.party);
          return (k === "D" || k === "R") && (s.distance - nearest.distance) <= 0.4;
        })
        .sort((a, b) => a.distance - b.distance)[0];
      if (majorWithin) nearest = majorWithin;
    }
  }

  return {
    year: ctx.year,
    candidates: scored,
    clearingBar,
    nearestByValues,
    nearest,
    valuesDecision: nearestByValues.ideologicalDistance <= clearingBar ? "vote" : "abstain",
    decision: nearest.distance <= clearingBar ? "vote" : "abstain",
  };
}
